 99→// --- browse tool ---
100→
101→func browseTool() mcpgo.Tool {
102→	return mcpgo.NewTool("browse",
103→		mcpgo.WithDescription("Get the full content of an item by its ID."),
104→		mcpgo.WithString("id", mcpgo.Required(), mcpgo.Description("Item UUID")),
105→	)
106→}
107→
108→func browseHandler(deps Deps) server.ToolHandlerFunc {
109→	return func(ctx context.Context, req mcpgo.CallToolRequest) (*mcpgo.CallToolResult, error) {
110→		claims, errResult := requireAuth(ctx)
111→		if errResult != nil {
112→			return errResult, nil
113→		}
114→
115→		if errResult := AllowedTool(ctx, "browse"); errResult != nil {
116→			auditToolCall(ctx, deps.Audit, claims, "browse", req.GetArguments(), true)
117→			return errResult, nil
118→		}
119→
120→		idStr := req.GetString("id", "")
121→		id, err := uuid.Parse(idStr)
122→		if err != nil {
123→			return mcpgo.NewToolResultError("invalid item ID: must be a valid UUID"), nil
124→		}
125→
126→		it, err := deps.Items.GetByID(ctx, claims.UserID, id)
127→		if err != nil {
128→			auditToolCall(ctx, deps.Audit, claims, "browse", req.GetArguments(), false)
129→			return mcpgo.NewToolResultError(fmt.Sprintf("failed to get item: %v", err)), nil
130→		}
131→
132→		// Check sensitivity
133→		if !SensitivityAllowed(ctx, it.Sensitivity) {
134→			auditToolCall(ctx, deps.Audit, claims, "browse", req.GetArguments(), true)
135→			return mcpgo.NewToolResultError("item sensitivity level exceeds API key permissions"), nil
136→		}
137→
138→		auditToolCall(ctx, deps.Audit, claims, "browse", req.GetArguments(), false)
139→		return mcpgo.NewToolResultText(formatItem(it)), nil
140→	}
141→}
