226→// auditToolCall logs a tool invocation to the audit log (best effort).
227→func auditToolCall(ctx context.Context, logger *audit.Logger, claims *auth.Claims, tool string, args map[string]any, denied bool) {
228→	if logger == nil {
229→		return
230→	}
231→
232→	client := auth.GetMCPClient(ctx)
233→	var clientID *uuid.UUID
234→	if client != nil {
235→		clientID = &client.ClientID
236→	}
237→
238→	var approved *bool
239→	if denied {
240→		f := false
241→		approved = &f
242→	}
243→
244→	logger.Log(ctx, audit.Entry{
245→		UserID:       claims.UserID,
246→		ClientID:     clientID,
247→		Action:       "mcp." + tool,
248→		ResourceType: "tool",
249→		Request:      args,
250→		Approved:     approved,
251→	})
252→}
