12→// formatSearchResults renders a search result set as markdown text.
13→func formatSearchResults(result *item.SearchResult) string {
14→	if len(result.Items) == 0 {
15→		return "No items found."
16→	}
17→
18→	var b strings.Builder
19→	fmt.Fprintf(&b, "Found %d item(s):\n\n", result.Total)
20→
21→	for _, it := range result.Items {
22→		b.WriteString(formatItemSummary(it))
23→		b.WriteString("\n")
24→	}
25→
26→	if result.HasMore {
27→		b.WriteString("_(more results available — increase limit or refine query)_\n")
28→	}
29→
30→	return b.String()
31→}
